import React, { createContext, useState, useEffect, useContext } from 'react';
import api from '../services/api';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('token'));
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (token) {
            // User data is already in localStorage, let's load it
            const savedUser = JSON.parse(localStorage.getItem('user'));
            if (savedUser) {
                setUser(savedUser);
            }
        }
        setLoading(false);
    }, [token]);

    const login = async (email, password) => {
        try {
            const { data } = await api.post('/auth/login', { email, password });
            setUser(data.user);
            setToken(data.token);
            localStorage.setItem('token', data.token);
            localStorage.setItem('user', JSON.stringify(data.user));
            return { success: true };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Login failed'
            };
        }
    };

    const googleLogin = async (tokenId) => {
        try {
            const { data } = await api.post('/auth/google', { tokenId });
            setUser(data.user);
            setToken(data.token);
            localStorage.setItem('token', data.token);
            localStorage.setItem('user', JSON.stringify(data.user));
            return { success: true };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Google login failed'
            };
        }
    };

    const resetPassword = async (email, newPassword) => {
        try {
            const { data } = await api.post('/auth/reset-password', { email, newPassword });
            return { success: true, message: data.message };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Password reset failed'
            };
        }
    };

    const register = async (userData) => {
        try {
            const { data } = await api.post('/auth/register', userData);
            // Do not set user or token so they must log in manually
            return { success: true };
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Registration failed'
            };
        }
    };

    const logout = () => {
        setUser(null);
        setToken(null);
        localStorage.removeItem('token');
        localStorage.removeItem('user');
    };

    const updateProfile = (updatedUserData) => {
        const newUser = { ...user, ...updatedUserData };
        setUser(newUser);
        localStorage.setItem('user', JSON.stringify(newUser));
    };

    return (
        <AuthContext.Provider value={{ user, token, loading, login, googleLogin, resetPassword, register, updateProfile, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import Calendar from 'react-calendar';
import 'react-calendar/dist/Calendar.css';
import { getTutorSessions, createSession, deleteSession } from '../services/sessionService';
import { toast } from 'react-toastify';

const TutorScheduleManager = ({ tutorId }) => {
    const [date, setDate] = useState(new Date());
    const [startTime, setStartTime] = useState('09:00');
    const [endTime, setEndTime] = useState('10:00');
    const [maxParticipants, setMaxParticipants] = useState(1);
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchSessions();
        // eslint-disable-next-line
    }, [tutorId]);

    const fetchSessions = async () => {
        try {
            setLoading(true);
            const data = await getTutorSessions(tutorId);
            // Assuming data is an array of sessions. Handle response format accordingly.
            setSessions(data.data || data);
        } catch (error) {
            toast.error('Failed to load sessions');
        } finally {
            setLoading(false);
        }
    };

    const handleCreateSession = async (e) => {
        e.preventDefault();
        try {
            await createSession({
                tutor: tutorId,
                date: date.toISOString(),
                startTime,
                endTime,
                maxParticipants,
            });
            toast.success('Session created successfully!');
            fetchSessions();
        } catch (error) {
            toast.error(error?.response?.data?.error || 'Failed to create session');
        }
    };

    const handleDeleteSession = async (sessionId) => {
        try {
            await deleteSession(sessionId);
            toast.success('Session deleted');
            fetchSessions();
        } catch (error) {
            toast.error('Failed to delete session');
        }
    };

    // Filter sessions for the selected date
    const selectedDateSessions = sessions.filter(
        (s) => new Date(s.date).toDateString() === date.toDateString()
    );

    return (
        <div className="text-slate-800 w-full font-sans">
            <div className="max-w-6xl mx-auto space-y-8">
                <header className="mb-8">
                    <h1 className="text-4xl font-extrabold text-slate-800">
                        Work Schedule
                    </h1>
                    <p className="text-slate-500 mt-2">Manage your availability, sessions, and participants efficiently.</p>
                </header>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

                    {/* Left Column: Calendar & Filters */}
                    <div className="lg:col-span-4 space-y-6">
                        <div className="bg-white p-6 rounded-[2rem] shadow-xl shadow-blue-50 border border-blue-100">
                            <h2 className="text-xl font-bold mb-4 text-slate-800">Select Date</h2>
                            <div className="rounded-2xl overflow-hidden border border-blue-50 bg-white p-2">
                                <Calendar
                                    onChange={setDate}
                                    value={date}
                                    className="w-full border-none shadow-none"
                                />
                            </div>
                            <div className="mt-4 p-4 bg-blue-50 rounded-2xl border border-blue-100">
                                <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Editing Shift For</p>
                                <p className="text-lg font-bold text-blue-600">{date.toDateString()}</p>
                            </div>
                        </div>
                    </div>

                    {/* Right Column: Creation Form & List */}
                    <div className="lg:col-span-8 space-y-8">

                        {/* Create Session Form */}
                        <div className="bg-white p-8 rounded-[2rem] shadow-xl shadow-blue-50 border border-blue-100">
                            <h2 className="text-2xl font-bold mb-6 text-slate-800 border-b border-blue-50 pb-3">Add Availability Slot</h2>
                            <form onSubmit={handleCreateSession} className="space-y-6">
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-sm font-bold text-slate-600 mb-2">Start Time</label>
                                        <input
                                            type="time"
                                            value={startTime}
                                            onChange={(e) => setStartTime(e.target.value)}
                                            className="w-full bg-blue-50/30 border border-blue-100 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-blue-400 transition-all font-medium"
                                            required
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-bold text-slate-600 mb-2">End Time</label>
                                        <input
                                            type="time"
                                            value={endTime}
                                            onChange={(e) => setEndTime(e.target.value)}
                                            className="w-full bg-blue-50/30 border border-blue-100 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-indigo-400 transition-all font-medium"
                                            required
                                        />
                                    </div>
                                    <div className="sm:col-span-2">
                                        <label className="block text-sm font-bold text-slate-600 mb-2">Max Participants</label>
                                        <input
                                            type="number"
                                            min="1"
                                            value={maxParticipants}
                                            onChange={(e) => setMaxParticipants(parseInt(e.target.value))}
                                            className="w-full bg-blue-50/30 border border-blue-100 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-blue-400 transition-all font-medium"
                                            required
                                        />
                                    </div>
                                </div>
                                <button
                                    type="submit"
                                    className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 px-6 rounded-2xl shadow-lg shadow-blue-200 transform transition hover:-translate-y-1 uppercase tracking-widest text-sm"
                                >
                                    Confirm Availability
                                </button>
                            </form>
                        </div>

                        {/* List of Sessions */}
                        <div className="bg-white p-8 rounded-[2rem] shadow-xl shadow-blue-50 border border-blue-100">
                            <h2 className="text-2xl font-bold mb-6 text-slate-800 flex items-center justify-between border-b border-blue-50 pb-3">
                                <span>Active Slots</span>
                                <span className="text-xs font-black px-3 py-1 bg-blue-50 rounded-full text-blue-600 uppercase tracking-widest">{selectedDateSessions.length} total</span>
                            </h2>

                            {loading ? (
                                <div className="animate-pulse space-y-4">
                                    <div className="h-20 bg-blue-50 rounded-2xl"></div>
                                    <div className="h-20 bg-blue-50 rounded-2xl"></div>
                                </div>
                            ) : selectedDateSessions.length === 0 ? (
                                <div className="text-center py-10 bg-blue-50/20 rounded-2xl border border-blue-100 border-dashed">
                                    <p className="text-slate-400 font-medium">No sessions scheduled for this date.</p>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {selectedDateSessions.map(session => (
                                        <div key={session._id} className="group flex flex-col sm:flex-row justify-between items-start sm:items-center p-5 bg-white rounded-2xl border border-blue-50 hover:border-blue-400/50 transition-all shadow-sm">
                                            <div className="mb-4 sm:mb-0">
                                                <div className="text-lg font-black text-slate-700">
                                                    {session.startTime} - {session.endTime}
                                                </div>
                                                <div className="text-xs mt-1 flex items-center gap-3">
                                                    <span className={`px-2 py-0.5 tracking-widest text-[10px] uppercase font-black rounded-lg border ${session.status === 'booked' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-green-50 text-green-600 border-green-100'}`}>
                                                        {session.status}
                                                    </span>
                                                    <span className="text-slate-400 font-medium">
                                                        Capacity: <span className="text-slate-700 font-bold">{session.currentParticipants}</span> / {session.maxParticipants}
                                                    </span>
                                                </div>
                                            </div>
                                            <button
                                                onClick={() => handleDeleteSession(session._id)}
                                                className="px-6 py-2 rounded-xl text-red-500 hover:bg-red-50 font-bold text-sm border border-transparent hover:border-red-100 transition-all"
                                            >
                                                Remove Slot
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                    </div>
                </div>
            </div>
        </div>
    );
};

export default TutorScheduleManager;

import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';
import { Link } from 'react-router-dom';

const AdminDashboard = () => {
    const [activeTab, setActiveTab] = useState('overview');
    const [stats, setStats] = useState(null);
    const [users, setUsers] = useState([]);
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchAdminData();
    }, []);

    const fetchAdminData = async () => {
        try {
            setLoading(true);
            const [statsRes, usersRes, sessionsRes] = await Promise.all([
                api.get('/admin/stats'),
                api.get('/admin/users'),
                api.get('/admin/sessions')
            ]);
            setStats(statsRes.data.stats);
            setUsers(usersRes.data.users);
            setSessions(sessionsRes.data.sessions);
        } catch (error) {
            toast.error('Failed to fetch admin data');
        } finally {
            setLoading(false);
        }
    };

    const handleBlockUser = async (userId, isBlocked) => {
        try {
            await api.put(`/admin/users/${userId}/status`, { isBlocked });
            toast.success(`User ${isBlocked ? 'blocked' : 'unblocked'} successfully`);
            fetchAdminData();
        } catch (error) {
            toast.error('Operation failed');
        }
    };

    const handleDeleteUser = async (userId) => {
        if (!window.confirm('Are you sure you want to delete this user? This cannot be undone.')) return;
        try {
            await api.delete(`/admin/users/${userId}`);
            toast.success('User deleted');
            fetchAdminData();
        } catch (error) {
            toast.error('Delete failed');
        }
    };

    if (loading) return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-slate-800"></div>
        </div>
    );

    return (
        <div className="min-h-screen bg-[#f8fafc] flex">
            {/* Left Sidebar */}
            <aside className="w-72 bg-slate-900 text-white flex flex-col shadow-2xl sticky top-0 h-screen">
                <div className="p-8 border-b border-slate-800">
                    <h1 className="text-2xl font-black tracking-tighter text-white flex items-center gap-2">
                        <span className="w-8 h-8 bg-blue-500 rounded-lg flex items-center justify-center text-sm italic">S</span>
                        STUEDU ADMIN
                    </h1>
                </div>
                <nav className="flex-1 p-6 space-y-2">
                    {[
                        { id: 'overview', label: 'Dashboard', icon: '­ƒôè' },
                        { id: 'users', label: 'User Control', icon: '­ƒæÑ' },
                        { id: 'sessions', label: 'Sessions', icon: '­ƒôà' },
                        { id: 'payments', label: 'Financials', icon: '­ƒÆ│' },
                        { id: 'ratings', label: 'Feedback', icon: 'Ô¡É' },
                    ].map(item => (
                        <button
                            key={item.id}
                            onClick={() => setActiveTab(item.id)}
                            className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all font-bold text-sm ${activeTab === item.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
                        >
                            <span className="text-xl">{item.icon}</span>
                            {item.label}
                        </button>
                    ))}
                </nav>
                <div className="p-6 border-t border-slate-800">
                    <Link to="/dashboard" className="flex items-center gap-3 text-slate-400 hover:text-white transition group font-bold text-sm">
                        <span className="group-hover:-translate-x-1 transition">ÔåÉ</span> Exit to System
                    </Link>
                </div>
            </aside>

            {/* Main Content Area */}
            <main className="flex-1 p-10 overflow-y-auto">
                <header className="flex justify-between items-end mb-10">
                    <div>
                        <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tight">
                            {activeTab.replace('-', ' ')}
                        </h2>
                        <p className="text-slate-400 font-medium">System-wide administrative control panel</p>
                    </div>
                    <div className="flex gap-4">
                        <button onClick={fetchAdminData} className="px-4 py-2 bg-white border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition shadow-sm">
                            Refresh Data
                        </button>
                    </div>
                </header>

                {/* Dashboard Tab */}
                {activeTab === 'overview' && (
                    <div className="space-y-10">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                            {[
                                { label: 'Total Users', value: stats?.users, color: 'blue', icon: '­ƒæÑ' },
                                { label: 'Active Sessions', value: stats?.sessions, color: 'indigo', icon: '­ƒôà' },
                                { label: 'Total Bookings', value: stats?.bookings, color: 'green', icon: 'Ô£à' },
                                { label: 'Est. Revenue', value: `$${stats?.revenue}`, color: 'amber', icon: '­ƒÆ░' },
                            ].map((s, i) => (
                                <div key={i} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/20 relative overflow-hidden group">
                                    <div className={`absolute top-0 right-0 p-4 text-4xl opacity-10 group-hover:scale-125 transition`}>{s.icon}</div>
                                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">{s.label}</p>
                                    <p className={`text-4xl font-black text-slate-800`}>{s.value}</p>
                                    <div className={`h-1 w-12 bg-${s.color}-500 mt-4 rounded-full`}></div>
                                </div>
                            ))}
                        </div>

                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/20">
                                <h3 className="text-xl font-black mb-6 flex items-center gap-3">
                                    <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
                                    Recent Registrations
                                </h3>
                                <div className="space-y-4">
                                    {users.slice(0, 5).map(u => (
                                        <div key={u._id} className="flex items-center justify-between p-4 bg-slate-50/50 rounded-2xl border border-slate-100 hover:border-blue-200 transition">
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-xl bg-blue-100 text-blue-600 flex items-center justify-center font-bold">
                                                    {u.firstName[0]}
                                                </div>
                                                <div>
                                                    <p className="font-bold text-slate-800 leading-none mb-1">{u.firstName} {u.lastName}</p>
