                                <div className="flex flex-col items-center justify-center h-full pb-8">
                                    <div className="w-48 h-48 rounded-full border-[12px] border-slate-50 flex flex-col items-center justify-center relative">
                                        <div className="absolute inset-0 border-[12px] border-blue-500 rounded-full border-t-transparent -rotate-45"></div>
                                        <p className="text-4xl font-black text-slate-800">82%</p>
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Growth Index</p>
                                    </div>
                                    <p className="mt-6 text-sm text-slate-400 font-medium max-w-[200px] text-center italic">
                                        "Platform scaling is optimal based on concurrent sessions."
                                    </p>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Users Tab */}
                {activeTab === 'users' && (
                    <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/20 overflow-hidden">
                        <table className="w-full text-left">
                            <thead className="bg-slate-50 border-b border-slate-100">
                                <tr>
                                    <th className="px-8 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Identity</th>
                                    <th className="px-8 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Access Role</th>
                                    <th className="px-8 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Trust Status</th>
                                    <th className="px-8 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest text-right">Operational Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {users.map(u => (
                                    <tr key={u._id} className="hover:bg-slate-50/50 transition">
                                        <td className="px-8 py-5">
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-xl bg-slate-100 overflow-hidden">
                                                    {u.profilePicture ? (
                                                        <img src={u.profilePicture} alt="" className="w-full h-full object-cover" />
                                                    ) : (
                                                        <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">{u.firstName[0]}</div>
                                                    )}
                                                </div>
                                                <div>
                                                    <p className="font-bold text-slate-800">{u.firstName} {u.lastName}</p>
                                                    <p className="text-xs text-slate-400">{u.email}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-8 py-5">
                                            <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${u.role === 'Admin' ? 'bg-amber-50 text-amber-600 border border-amber-100' : u.role === 'Host' ? 'bg-blue-50 text-blue-600 border border-blue-100' : 'bg-slate-100 text-slate-600'}`}>
                                                {u.role}
                                            </span>
                                        </td>
                                        <td className="px-8 py-5">
                                            <div className="flex items-center gap-2">
                                                <div className={`w-2 h-2 rounded-full ${u.isBlocked ? 'bg-red-500' : 'bg-green-500'}`}></div>
                                                <span className="text-xs font-bold text-slate-700">{u.isBlocked ? 'Blocked' : 'Active'}</span>
                                            </div>
                                        </td>
                                        <td className="px-8 py-5 text-right">
                                            <div className="flex justify-end gap-2">
                                                <button
                                                    onClick={() => handleBlockUser(u._id, !u.isBlocked)}
                                                    className={`px-3 py-2 rounded-xl text-xs font-black transition ${u.isBlocked ? 'bg-green-50 text-green-600 hover:bg-green-100' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
                                                >
                                                    {u.isBlocked ? 'Unblock' : 'Block'}
                                                </button>
                                                <button
                                                    onClick={() => handleDeleteUser(u._id)}
                                                    className="px-3 py-2 bg-red-50 text-red-600 hover:bg-red-100 rounded-xl text-xs font-black transition"
                                                >
                                                    Delete
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}

                {/* Sessions Tab */}
                {activeTab === 'sessions' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {sessions.map(s => (
                            <div key={s._id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/20">
                                <div className="flex justify-between items-start mb-4">
                                    <div className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${s.status === 'available' ? 'bg-green-50 text-green-600' : 'bg-blue-50 text-blue-600'}`}>
                                        {s.status}
                                    </div>
                                    <p className="text-[10px] font-black text-slate-400">{new Date(s.date).toLocaleDateString()}</p>
                                </div>
                                <h4 className="text-lg font-black text-slate-800 leading-tight mb-4">
                                    {s.startTime} - {s.endTime}
                                </h4>
                                <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl">
