                                                    <p className="text-lg font-bold text-slate-700">{formData.firstName} {formData.lastName}</p>
                                                </div>
                                                <div className="p-4 bg-blue-50/50 rounded-2xl border border-blue-100/50">
                                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Email Address</p>
                                                    <p className="text-lg font-bold text-slate-700">{formData.email}</p>
                                                </div>
                                                <div className="p-4 bg-blue-50/50 rounded-2xl border border-blue-100/50">
                                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Contact Number</p>
                                                    <p className="text-lg font-bold text-slate-700">{formData.contactNumber || 'Not provided'}</p>
                                                </div>
                                                <div className="p-4 bg-blue-50/50 rounded-2xl border border-blue-100/50">
                                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Account Role</p>
                                                    <p className="text-lg font-bold text-blue-600">{formData.role || 'User'}</p>
                                                </div>
                                            </div>

                                            <div className="flex justify-end pt-4">
                                                <button
                                                    type="button"
                                                    onClick={() => setIsEditing(true)}
                                                    className="px-8 py-3 bg-blue-500 hover:bg-blue-600 text-white font-bold rounded-xl shadow-lg transition transform hover:-translate-y-0.5"
                                                >
                                                    Edit Profile Details
                                                </button>
                                            </div>
                                        </div>
                                    ) : (
                                        // Edit Mode: Display Form
                                        <>
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                                <div>
                                                    <label className="block text-sm font-medium text-slate-600 mb-2">First Name</label>
                                                    <input
                                                        type="text"
                                                        name="firstName"
                                                        value={formData.firstName}
                                                        onChange={onChange}
                                                        required
                                                        className="w-full bg-blue-50/30 border border-blue-100 rounded-xl px-4 py-3 text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-400 transition"
                                                    />
                                                </div>
                                                <div>
                                                    <label className="block text-sm font-medium text-slate-600 mb-2">Last Name</label>
                                                    <input
                                                        type="text"
                                                        name="lastName"
                                                        value={formData.lastName}
                                                        onChange={onChange}
                                                        required
                                                        className="w-full bg-blue-50/30 border border-blue-100 rounded-xl px-4 py-3 text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-400 transition"
                                                    />
                                                </div>
                                                <div>
                                                    <label className="block text-sm font-medium text-slate-600 mb-2">Email Address</label>
                                                    <input
                                                        type="email"
                                                        name="email"
                                                        value={formData.email}
                                                        onChange={onChange}
                                                        required
                                                        className="w-full bg-blue-50/30 border border-blue-100 rounded-xl px-4 py-3 text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-400 transition"
                                                    />
                                                </div>
                                                <div>
                                                    <label className="block text-sm font-medium text-slate-600 mb-2">Contact Number</label>
                                                    <input
                                                        type="text"
                                                        name="contactNumber"
                                                        value={formData.contactNumber}
                                                        onChange={onChange}
                                                        required
                                                        className="w-full bg-blue-50/30 border border-blue-100 rounded-xl px-4 py-3 text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-400 transition"
                                                    />
                                                </div>
                                            </div>

                                            <div className="pt-8 border-t border-blue-50">
                                                <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                                                    <span className="w-8 h-8 rounded-lg bg-indigo-100 text-indigo-600 flex items-center justify-center">­ƒöö</span>
                                                    Notification Preferences
                                                </h2>
                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                    <label className="flex items-center justify-between p-4 bg-blue-50/30 rounded-2xl border border-blue-100 cursor-pointer hover:border-blue-400 transition">
                                                        <span className="text-slate-800 font-medium">Email</span>
                                                        <input type="checkbox" name="notif_email" checked={formData.notificationPreferences.email} onChange={onChange} className="w-5 h-5 rounded text-blue-500" />
                                                    </label>
                                                    <label className="flex items-center justify-between p-4 bg-blue-50/30 rounded-2xl border border-blue-100 cursor-pointer hover:border-blue-400 transition">
                                                        <span className="text-slate-800 font-medium">SMS</span>
                                                        <input type="checkbox" name="notif_sms" checked={formData.notificationPreferences.sms} onChange={onChange} className="w-5 h-5 rounded text-blue-500" />
                                                    </label>
                                                </div>
                                            </div>

                                            <div className="pt-8 flex gap-4">
                                                <button
                                                    type="submit"
                                                    disabled={saving}
                                                    className={`flex-1 py-4 px-6 rounded-2xl text-white font-bold transition transform hover:-translate-y-1 shadow-lg shadow-blue-200 ${saving ? 'bg-slate-400 cursor-not-allowed' : 'bg-blue-500 hover:bg-blue-600'}`}
                                                >
                                                    {saving ? 'Saving Changes...' : 'Save All Settings'}
                                                </button>
                                                <button
                                                    type="button"
                                                    onClick={() => setIsEditing(false)}
                                                    className="px-6 py-4 bg-slate-100 hover:bg-slate-200 text-slate-500 font-bold rounded-2xl transition"
                                                >
                                                    Cancel
                                                </button>
                                            </div>
                                        </>
                                    )}
                                </section>
                            </form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Profile;
